prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?origId ?normId ?modelName WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model bbo:name ?modelName . }
  FILTER(CONTAINS(STR(?normId), "2d225c9ff86b443c9f6bc6cfe687afbc") || CONTAINS(STR(?origId), "2d225c9ff86b443c9f6bc6cfe687afbc"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName ?choreo ?choreoName ?source ?sourceName ?target ?targetName WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task bbo:name ?taskName .
  FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("Probe ausliefern")))
  ?task tai:belongsTo ?choreo .
  ?choreo a bboExt:Choreography .
  OPTIONAL { ?choreo bbo:name ?choreoName . }

  OPTIONAL {
    ?flow a bbo:SequenceFlow .
    ?flow bbo:has_sourceRef ?task .
    ?flow bbo:has_targetRef ?target .
    OPTIONAL { ?target bbo:name ?targetName . }
  }

  OPTIONAL {
    ?inFlow a bbo:SequenceFlow .
    ?inFlow bbo:has_targetRef ?task .
    ?inFlow bbo:has_sourceRef ?source .
    OPTIONAL { ?source bbo:name ?sourceName . }
  }
}
LIMIT 25
